export function parseApiValue(val: any): number {
    if (typeof val === 'number') return val;
    const num = parseFloat(String(val).replace(/[R$\s]/g, '').replace(/\./g, '').replace(',', '.'));
    return isNaN(num) ? 0 : num;
}

